import { useState } from 'react';
import { useQuery, useMutation } from '@tanstack/react-query';
import { supabase, supabaseUrl } from '@/integrations/supabase/client';
import { useAuth } from '@/contexts/AuthContext';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from '@/components/ui/select';
import {
    FileText,
    Download,
    Loader2,
    Calendar,
    BarChart3,
    Megaphone,
    Image,
    FileCheck,
    ExternalLink,
    Clock
} from 'lucide-react';
import { format, subDays } from 'date-fns';
import { ptBR } from 'date-fns/locale';
import { toast } from 'sonner';

interface Report {
    id: string;
    report_type: string;
    date_from: string;
    date_to: string;
    created_at: string;
}

const REPORT_TYPES = [
    { value: 'performance', label: 'Performance Geral', icon: BarChart3 },
    { value: 'campaigns', label: 'Campanhas', icon: Megaphone },
    { value: 'creatives', label: 'Criativos', icon: Image },
    { value: 'audits', label: 'Auditorias', icon: FileCheck },
];

export default function Relatorios() {
    const { user } = useAuth();
    const companyId = user?.company?.id;
    const [reportType, setReportType] = useState<string>('performance');
    const [dateFrom, setDateFrom] = useState(format(subDays(new Date(), 30), 'yyyy-MM-dd'));
    const [dateTo, setDateTo] = useState(format(new Date(), 'yyyy-MM-dd'));

    // Fetch report history
    const { data: reports = [], isLoading } = useQuery({
        queryKey: ['reports', companyId],
        queryFn: async () => {
            if (!companyId) throw new Error('No company ID');
            const { data, error } = await supabase
                .from('reports')
                .select('id, report_type, date_from, date_to, created_at')
                .eq('company_id', companyId)
                .order('created_at', { ascending: false })
                .limit(20);
            if (error) throw error;
            return data as Report[];
        },
        enabled: !!companyId,
    });

    const generateReport = useMutation({
        mutationFn: async () => {
            const { data: { session } } = await supabase.auth.getSession();
            if (!session) throw new Error('No session');

            const response = await fetch(
                `${supabaseUrl}/functions/v1/generate-report`,
                {
                    method: 'POST',
                    headers: {
                        'Authorization': `Bearer ${session.access_token}`,
                        'Content-Type': 'application/json',
                    },
                    body: JSON.stringify({
                        report_type: reportType,
                        date_from: dateFrom,
                        date_to: dateTo,
                    }),
                }
            );

            if (!response.ok) {
                const error = await response.json();
                throw new Error(error.error || 'Report generation failed');
            }

            const html = await response.text();
            return html;
        },
        onSuccess: (html) => {
            // Open report in new window
            const win = window.open('', '_blank');
            if (win) {
                win.document.write(html);
                win.document.close();
            }
            toast.success('Relatório gerado com sucesso');
        },
        onError: (error) => {
            toast.error(`Erro ao gerar relatório: ${error.message}`);
        },
    });

    const getReportTypeLabel = (type: string) => {
        return REPORT_TYPES.find(t => t.value === type)?.label || type;
    };

    const getReportIcon = (type: string) => {
        const Icon = REPORT_TYPES.find(t => t.value === type)?.icon || FileText;
        return <Icon className="w-4 h-4" />;
    };

    return (
        <div className="p-8 max-w-6xl mx-auto">
            <div className="mb-8">
                <h1 className="text-2xl font-bold text-ch-white mb-2">Relatórios</h1>
                <p className="text-ch-text-muted">
                    Gere relatórios detalhados de performance, campanhas, criativos e auditorias.
                </p>
            </div>

            {/* Report Generator */}
            <div className="glass rounded-xl p-6 mb-8">
                <h2 className="text-lg font-semibold text-ch-white mb-4 flex items-center gap-2">
                    <FileText className="w-5 h-5 text-ch-orange" />
                    Gerar Novo Relatório
                </h2>

                <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
                    <div className="space-y-2">
                        <Label>Tipo de Relatório</Label>
                        <Select value={reportType} onValueChange={setReportType}>
                            <SelectTrigger className="bg-ch-dark-gray border-ch-dark-gray">
                                <SelectValue />
                            </SelectTrigger>
                            <SelectContent>
                                {REPORT_TYPES.map(t => (
                                    <SelectItem key={t.value} value={t.value}>
                                        <div className="flex items-center gap-2">
                                            <t.icon className="w-4 h-4" />
                                            {t.label}
                                        </div>
                                    </SelectItem>
                                ))}
                            </SelectContent>
                        </Select>
                    </div>

                    <div className="space-y-2">
                        <Label>Data Início</Label>
                        <Input
                            type="date"
                            value={dateFrom}
                            onChange={(e) => setDateFrom(e.target.value)}
                            className="bg-ch-dark-gray border-ch-dark-gray"
                        />
                    </div>

                    <div className="space-y-2">
                        <Label>Data Fim</Label>
                        <Input
                            type="date"
                            value={dateTo}
                            onChange={(e) => setDateTo(e.target.value)}
                            className="bg-ch-dark-gray border-ch-dark-gray"
                        />
                    </div>

                    <div className="flex items-end">
                        <Button
                            onClick={() => generateReport.mutate()}
                            disabled={generateReport.isPending}
                            className="w-full bg-ch-orange hover:bg-ch-orange/90"
                        >
                            {generateReport.isPending ? (
                                <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                            ) : (
                                <Download className="w-4 h-4 mr-2" />
                            )}
                            Gerar Relatório
                        </Button>
                    </div>
                </div>
            </div>

            {/* Report History */}
            <div className="glass rounded-xl p-6">
                <h2 className="text-lg font-semibold text-ch-white mb-4 flex items-center gap-2">
                    <Clock className="w-5 h-5 text-ch-orange" />
                    Histórico de Relatórios
                </h2>

                {isLoading ? (
                    <div className="flex items-center justify-center py-8">
                        <Loader2 className="w-6 h-6 animate-spin text-ch-orange" />
                    </div>
                ) : reports.length > 0 ? (
                    <div className="space-y-2">
                        {reports.map((report) => (
                            <div
                                key={report.id}
                                className="bg-ch-dark-gray rounded-lg p-4 flex items-center gap-4"
                            >
                                <div className="p-2 bg-ch-gray rounded-lg text-ch-orange">
                                    {getReportIcon(report.report_type)}
                                </div>
                                <div className="flex-1 min-w-0">
                                    <p className="font-medium text-ch-white">
                                        {getReportTypeLabel(report.report_type)}
                                    </p>
                                    <p className="text-sm text-ch-text-dimmed">
                                        {format(new Date(report.date_from), 'dd/MM/yyyy', { locale: ptBR })} -{' '}
                                        {format(new Date(report.date_to), 'dd/MM/yyyy', { locale: ptBR })}
                                    </p>
                                </div>
                                <div className="text-right">
                                    <p className="text-xs text-ch-text-dimmed">
                                        {format(new Date(report.created_at), "dd/MM/yyyy 'às' HH:mm", { locale: ptBR })}
                                    </p>
                                </div>
                            </div>
                        ))}
                    </div>
                ) : (
                    <div className="text-center py-8">
                        <FileText className="w-12 h-12 text-ch-text-dimmed mx-auto mb-4" />
                        <p className="text-ch-text-muted">Nenhum relatório gerado ainda.</p>
                    </div>
                )}
            </div>
        </div>
    );
}

import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { User, Shield, Sliders } from 'lucide-react';
import { ProfileForm } from '@/components/settings/ProfileForm';
import { SecurityForm } from '@/components/settings/SecurityForm';
import { PreferencesForm } from '@/components/settings/PreferencesForm';
import { motion } from 'framer-motion';

const container = {
    hidden: { opacity: 0 },
    show: {
        opacity: 1,
        transition: {
            staggerChildren: 0.1
        }
    }
};

const item = {
    hidden: { y: 20, opacity: 0 },
    show: { y: 0, opacity: 1 }
};

export default function Settings() {
    return (
        <motion.div
            initial="hidden"
            animate="show"
            variants={container}
            className="space-y-8 p-8"
        >
            <div className="flex items-center justify-between">
                <div>
                    <motion.h1 variants={item} className="text-3xl font-black text-ch-white tracking-tight uppercase">
                        Configurações
                    </motion.h1>
                    <motion.p variants={item} className="text-ch-text-muted font-medium mt-1">
                        Gerencie seu perfil, segurança e preferências.
                    </motion.p>
                </div>
            </div>

            <motion.div variants={item}>
                <Tabs defaultValue="profile" className="space-y-6">
                    <TabsList className="bg-white/5 border border-white/10 p-1 rounded-xl w-full sm:w-auto flex flex-wrap sm:flex-nowrap gap-2 sm:gap-0">
                        <TabsTrigger
                            value="profile"
                            className="data-[state=active]:bg-ch-orange data-[state=active]:text-black h-10 px-6 rounded-lg text-ch-text-dimmed uppercase font-black text-[10px] tracking-widest transition-all flex-1 sm:flex-none"
                        >
                            <User className="w-3.5 h-3.5 mr-2" />
                            Perfil
                        </TabsTrigger>
                        <TabsTrigger
                            value="security"
                            className="data-[state=active]:bg-ch-orange data-[state=active]:text-black h-10 px-6 rounded-lg text-ch-text-dimmed uppercase font-black text-[10px] tracking-widest transition-all flex-1 sm:flex-none"
                        >
                            <Shield className="w-3.5 h-3.5 mr-2" />
                            Segurança
                        </TabsTrigger>
                        <TabsTrigger
                            value="preferences"
                            className="data-[state=active]:bg-ch-orange data-[state=active]:text-black h-10 px-6 rounded-lg text-ch-text-dimmed uppercase font-black text-[10px] tracking-widest transition-all flex-1 sm:flex-none"
                        >
                            <Sliders className="w-3.5 h-3.5 mr-2" />
                            Preferências
                        </TabsTrigger>
                    </TabsList>

                    <TabsContent value="profile" className="outline-none">
                        <ProfileForm />
                    </TabsContent>

                    <TabsContent value="security" className="outline-none">
                        <SecurityForm />
                    </TabsContent>

                    <TabsContent value="preferences" className="outline-none">
                        <PreferencesForm />
                    </TabsContent>
                </Tabs>
            </motion.div>
        </motion.div>
    );
}

import { useState } from 'react';
import { useAuth } from '@/contexts/AuthContext';
import { useCompanyUsers, useUpdateUser, useRemoveUser } from '@/hooks/useUsers';
import { Button } from '@/components/ui/button';
import {
    DropdownMenu,
    DropdownMenuContent,
    DropdownMenuItem,
    DropdownMenuTrigger,
} from '@/components/ui/dropdown-menu';
import {
    Users,
    MoreHorizontal,
    Loader2,
    Shield,
    Trash2,
    Edit2,
    User
} from 'lucide-react';
import { formatDistanceToNow } from 'date-fns';
import { ptBR } from 'date-fns/locale';

export default function Usuarios() {
    const { user: currentUser } = useAuth();
    const { data: users, isLoading } = useCompanyUsers();
    const updateUser = useUpdateUser();
    const removeUser = useRemoveUser();

    const handleRoleChange = (userId: string, newRole: 'super_admin' | 'company_admin' | 'operador') => {
        updateUser.mutate({ userId, updates: { role: newRole } });
    };

    const handleRemove = (userId: string, userName: string) => {
        if (confirm(`Tem certeza que deseja desativar ${userName}?`)) {
            removeUser.mutate(userId);
        }
    };

    const getRoleBadge = (role: string) => {
        const colors: Record<string, string> = {
            super_admin: 'bg-purple-500/10 text-purple-500',
            company_admin: 'bg-blue-500/10 text-blue-500',
            operador: 'bg-green-500/10 text-green-500',
        };
        const labels: Record<string, string> = {
            super_admin: 'Super Admin',
            company_admin: 'Admin',
            operador: 'Operador',
        };
        return (
            <span className={`text-xs px-2 py-1 rounded-full ${colors[role] || 'bg-gray-500/10 text-gray-400'}`}>
                {labels[role] || role}
            </span>
        );
    };

    const activeUsers = users?.filter(u => u.is_active) || [];
    const inactiveUsers = users?.filter(u => !u.is_active) || [];

    return (
        <div className="p-6 space-y-6">
            {/* Header */}
            <div className="flex items-center justify-between">
                <div>
                    <h1 className="text-2xl font-bold text-ch-white">Usuários</h1>
                    <p className="text-ch-text-muted">
                        Gerencie os membros da sua equipe
                    </p>
                </div>
            </div>

            {/* Stats */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                <div className="glass rounded-xl p-5">
                    <div className="flex items-center gap-3">
                        <div className="p-2 bg-ch-orange/10 rounded-lg">
                            <Users className="w-5 h-5 text-ch-orange" />
                        </div>
                        <div>
                            <p className="text-2xl font-bold text-ch-white">{activeUsers.length}</p>
                            <p className="text-sm text-ch-text-muted">Usuários Ativos</p>
                        </div>
                    </div>
                </div>
                <div className="glass rounded-xl p-5">
                    <div className="flex items-center gap-3">
                        <div className="p-2 bg-purple-500/10 rounded-lg">
                            <Shield className="w-5 h-5 text-purple-500" />
                        </div>
                        <div>
                            <p className="text-2xl font-bold text-ch-white">
                                {activeUsers.filter(u => u.role === 'company_admin' || u.role === 'super_admin').length}
                            </p>
                            <p className="text-sm text-ch-text-muted">Administradores</p>
                        </div>
                    </div>
                </div>
                <div className="glass rounded-xl p-5">
                    <div className="flex items-center gap-3">
                        <div className="p-2 bg-gray-500/10 rounded-lg">
                            <User className="w-5 h-5 text-gray-500" />
                        </div>
                        <div>
                            <p className="text-2xl font-bold text-ch-white">{inactiveUsers.length}</p>
                            <p className="text-sm text-ch-text-muted">Inativos</p>
                        </div>
                    </div>
                </div>
            </div>

            {/* Users Table */}
            <div className="glass rounded-xl overflow-hidden">
                <div className="p-4 border-b border-white/5">
                    <h2 className="font-semibold text-ch-white">Membros da Equipe</h2>
                </div>

                {isLoading ? (
                    <div className="p-8 flex items-center justify-center">
                        <Loader2 className="w-6 h-6 animate-spin text-ch-orange" />
                    </div>
                ) : activeUsers.length > 0 ? (
                    <div className="divide-y divide-white/5">
                        {activeUsers.map((user) => (
                            <div key={user.id} className="p-4 flex items-center justify-between hover:bg-white/5 transition-colors">
                                <div className="flex items-center gap-4">
                                    <div className="w-10 h-10 rounded-full bg-ch-dark-gray flex items-center justify-center overflow-hidden">
                                        {user.avatar_url ? (
                                            <img src={user.avatar_url} alt="" className="w-full h-full object-cover" />
                                        ) : (
                                            <span className="text-ch-white font-medium">
                                                {user.first_name?.charAt(0)}{user.last_name?.charAt(0)}
                                            </span>
                                        )}
                                    </div>
                                    <div>
                                        <p className="font-medium text-ch-white">
                                            {user.first_name} {user.last_name}
                                            {user.id === currentUser?.id && (
                                                <span className="ml-2 text-xs text-ch-text-dimmed">(você)</span>
                                            )}
                                        </p>
                                        <p className="text-sm text-ch-text-dimmed">{user.email}</p>
                                    </div>
                                </div>

                                <div className="flex items-center gap-4">
                                    {getRoleBadge(user.role)}

                                    <span className="text-xs text-ch-text-dimmed">
                                        {user.last_login_at
                                            ? `Último acesso: ${formatDistanceToNow(new Date(user.last_login_at), { addSuffix: true, locale: ptBR })}`
                                            : 'Nunca acessou'
                                        }
                                    </span>

                                    {user.id !== currentUser?.id && (
                                        <DropdownMenu>
                                            <DropdownMenuTrigger asChild>
                                                <Button variant="ghost" size="icon" className="h-8 w-8">
                                                    <MoreHorizontal className="w-4 h-4" />
                                                </Button>
                                            </DropdownMenuTrigger>
                                            <DropdownMenuContent align="end">
                                                <DropdownMenuItem onClick={() => handleRoleChange(user.id, 'company_admin')}>
                                                    <Shield className="w-4 h-4 mr-2" />
                                                    Tornar Admin
                                                </DropdownMenuItem>
                                                <DropdownMenuItem onClick={() => handleRoleChange(user.id, 'operador')}>
                                                    <Edit2 className="w-4 h-4 mr-2" />
                                                    Tornar Operador
                                                </DropdownMenuItem>
                                                <DropdownMenuItem
                                                    onClick={() => handleRemove(user.id, `${user.first_name} ${user.last_name}`)}
                                                    className="text-red-500 focus:text-red-500"
                                                >
                                                    <Trash2 className="w-4 h-4 mr-2" />
                                                    Desativar
                                                </DropdownMenuItem>
                                            </DropdownMenuContent>
                                        </DropdownMenu>
                                    )}
                                </div>
                            </div>
                        ))}
                    </div>
                ) : (
                    <div className="p-8 text-center">
                        <Users className="w-12 h-12 text-ch-text-dimmed mx-auto mb-4" />
                        <p className="text-ch-text-muted">Nenhum usuário encontrado.</p>
                    </div>
                )}
            </div>
        </div>
    );
}

